class Solution { public int longestPalindrome(String s, String t) { int maxLength = 0; for (int i = 0; i <= s.length(); i++) { for (int j = 0; j <= t.length(); j++) { String combined = s.substring(0, i) + t.substring(j); if (isPalindrome(combined)) { maxLength = Math.max(maxLength, combined.length()); } } } return maxLength; } private boolean isPalindrome(String str) { int left = 0, right = str.length() - 1; while (left < right) { if (str.charAt(left) != str.charAt(right)) return false; left++; right--; } return true; } }